def find_maximum(lst):
    if len(lst) == 1:
        return lst[0]
    max_of_rest = find_maximum(lst[1:])
    if lst[0] >= max_of_rest:
        return lst[0]
    return max_of_rest

input_line = input().split()
numbers = []
for num in input_line:
    numbers.append(int(num))

result = find_maximum(numbers)
print(result)
